// UploadToS3 uploads a file to S3 using params from GetUploadParams.
// This handles step 2 of the 3-step upload flow:
//   1. Call Common.GetUploadParams() to get signing params and direct_url
//   2. Call Common.UploadToS3() with those params (this method)
//   3. Use the key to attach the file to a message or other entity
func (s *CommonService) UploadToS3(ctx context.Context, uploadParams *UploadParams, file io.Reader, filename string) error {
	var body bytes.Buffer
	writer := multipart.NewWriter(&body)

	key := strings.Replace(uploadParams.Key, "${filename}", filename, 1)

	_ = writer.WriteField("Content-Disposition", uploadParams.ContentMinusDisposition)
	_ = writer.WriteField("acl", uploadParams.ACL)
	_ = writer.WriteField("policy", uploadParams.Policy)
	_ = writer.WriteField("x-amz-credential", uploadParams.XMinusAmzMinusCredential)
	_ = writer.WriteField("x-amz-algorithm", uploadParams.XMinusAmzMinusAlgorithm)
	_ = writer.WriteField("x-amz-date", uploadParams.XMinusAmzMinusDate)
	_ = writer.WriteField("x-amz-signature", uploadParams.XMinusAmzMinusSignature)
	_ = writer.WriteField("key", key)

	part, err := writer.CreateFormFile("file", filename)
	if err != nil {
		return err
	}
	if _, err := io.Copy(part, file); err != nil {
		return err
	}
	if err := writer.Close(); err != nil {
		return err
	}

	req, err := http.NewRequestWithContext(ctx, "POST", uploadParams.DirectURL, &body)
	if err != nil {
		return err
	}
	req.Header.Set("Content-Type", writer.FormDataContentType())

	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusCreated {
		return fmt.Errorf("upload failed with status %d", resp.StatusCode)
	}
	return nil
}

// Download retrieves the download URL for a completed export.
// Returns the redirect Location URL without following the redirect.
func (s *CommonService) Download(ctx context.Context, id int32) (string, error) {
	httpClient := &http.Client{
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	reqURL := fmt.Sprintf("%s/chats/exports/%d", s.serverURL, id)
	req, err := http.NewRequestWithContext(ctx, "GET", reqURL, nil)
	if err != nil {
		return "", err
	}
	req.Header.Set("Authorization", "Bearer "+s.token)

	resp, err := httpClient.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusFound {
		return "", fmt.Errorf("expected 302 redirect, got %d", resp.StatusCode)
	}

	location := resp.Header.Get("Location")
	if location == "" {
		return "", fmt.Errorf("no Location header in redirect response")
	}
	return location, nil
}
